import React from "react";
import { BarChart3, Volume2, Eye, Activity } from "lucide-react";

// Utility function to format numbers with commas
const formatNumber = (num) => {
  if (!num && num !== 0) return "-";
  return Number(num).toLocaleString();
};

const MetricCard = ({ label, value, icon: Icon, trend, subValue }) => (
  <div className="group bg-white rounded-2xl p-4 shadow-sm border border-gray-100 hover:shadow-lg hover:border-blue-200 transition-all duration-300 hover:-translate-y-1">
    <div className="flex items-start justify-between mb-3">
      <div className="flex items-center gap-2">
        <div className="p-2 bg-blue-50 rounded-xl group-hover:bg-blue-100 transition-colors">
          <Icon size={16} className="text-blue-600" />
        </div>
        <div className="text-xs font-medium text-gray-500 uppercase tracking-wide">{label}</div>
      </div>
      {trend !== undefined && (
        <div className={`flex items-center text-xs px-2 py-1 rounded-full ${trend > 0 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
          {trend > 0 ? `+${trend}` : trend < 0 ? `${trend}` : '0'}
        </div>
      )}
    </div>
    <div className="space-y-1">
      <div className="text-xl font-bold text-gray-900">{value}</div>
      {subValue && <div className="text-xs text-gray-500">{subValue}</div>}
    </div>
  </div>
);

// Example parent component
const MetricsDashboard = ({ selectedCompany }) => {
  if (!selectedCompany) return <div>Loading...</div>;

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
      <MetricCard 
        label="Current Price" 
        value={`₹${formatNumber(selectedCompany.current_price)}`} 
        icon={BarChart3} 
        trend={selectedCompany.price_change} // optional
      />
      <MetricCard 
        label="Volume" 
        value={formatNumber(selectedCompany.volume)} 
        icon={Volume2} 
      />
      <MetricCard 
        label="P/E Ratio" 
        value={formatNumber(selectedCompany.pe)} 
        icon={Eye} 
      />
      <MetricCard 
        label="Market Cap" 
        value={`₹${formatNumber(selectedCompany.market_cap)}`} 
        icon={Activity} 
        subValue={`Prev: ₹${formatNumber(selectedCompany.market_cap_previous)}`} // optional
      />
    </div>
  );
};

export default MetricsDashboard;
